/* eslint-disable @typescript-eslint/no-misused-promises */

import React, { useState, useEffect } from "react";
import {
  showApiError,
  showSuccess,
  showLoading,
  closeSwal,
} from "../../utils/alert";

import { createItemStock } from "../../api/stockApi";
import { getStockById } from "../../api/stockItemApi";
import Modal from "../ui/modal/modal";
import { Button } from "../../components/ui/modal/formComponent";
import SearchSelect from "../ui/modal/SearchSelect";
import { getAllItems } from "../../api/itemApi";

type FormState = Record<string, any>;

const emptyForm: Record<string, any> = {
  id: "",
  itemName: "",
  itemGroup: "",
  itemClassCode: "",
  itemTypeCode: "",
  originNationCode: "",
  packagingUnitCode: "",
  svcCharge: "Y",
  ins: "Y",
  sellingPrice: 0,
  buyingPrice: 0,
  unitOfMeasureCd: "Nos",
  description: "",
  sku: "",
  taxPreference: "",
  preferredVendor: "",
  salesAccount: "",
  purchaseAccount: "",
  taxCategory: "Non-Export",
  taxType: "",
  taxCode: "",
  taxName: "",
  taxDescription: "",
  taxPerct: "",
  dimensionUnit: "",
  weight: "",
  valuationMethod: "",
  trackingMethod: "",
  reorderLevel: "",
  minStockLevel: "",
  maxStockLevel: "",
  brand: "",
  weightUnit: "",
  dimensionLength: "",
  dimensionWidth: "",
  dimensionHeight: "",
};

const ItemModal: React.FC<{
  isOpen: boolean;
  onClose: () => void;
  // onSubmit?: (data: Record<string, any>) => void;
  onSubmit?: () => void;
  initialData?: Record<string, any> | null;
  isEditMode?: boolean;
}> = ({ isOpen, onClose, onSubmit, initialData, isEditMode = false }) => {
  const [form, setForm] = useState<FormState>(emptyForm);
  const [loading, setLoading] = useState(false);
  const [itemOptions, setItemOptions] = useState<
    Array<{ label: string; value: string; id: string; itemClassCode?: string }>
  >([]);
  // Fetch all available items for dropdown on open
  useEffect(() => {
    if (!isOpen) return;

    (async () => {
      try {
        const response = await getAllItems(1, 1000);

        const items = response?.data || [];

        const mappedOptions = items
          .filter((item: any) => {
            const t = String(item?.itemType ?? item?.item_type ?? "").trim();
            return t === "1" || t === "2";
          })
          .map((item: any) => ({
            label: String(item?.itemName ?? item?.item_name ?? "").trim(),
            value: String(item?.id ?? item?.name ?? "").trim(),
            id: String(item?.id ?? item?.name ?? "").trim(),
            itemClassCode: String(
              item?.itemClassCode ?? item?.item_class_code ?? "",
            ).trim(),
          }));

        setItemOptions(mappedOptions);
      } catch (err) {
        console.error("Item fetch failed:", err);
        setItemOptions([]);
      }
    })();
  }, [isOpen]);

  useEffect(() => {
    if (!form.id) return;

    getStockById(form.id).then((res) => {
      console.log("Full Response:", res);

      const item = res?.items?.[0];

      if (!item) return;

      setForm((prev) => ({
        ...prev,
        itemClassCode: item.itemCode || "",
        quantity: item.quantity || "",
        rate: item.rate || "",
        warehouse: item.warehouse || "",
      }));
    });
  }, [form.id]);

  const [activeTab, setActiveTab] = useState<
    "details" | "taxDetails" | "inventoryDetails"
  >("details");

  useEffect(() => {
    if (!isOpen) return;

    if (isEditMode && initialData) {
      setForm({ ...emptyForm, ...initialData });
    } else {
      setForm(emptyForm);
    }

    setActiveTab("details");
  }, [isOpen, isEditMode, initialData]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    try {
      if (loading) return;

      if (!form.id) {
        showApiError("Please select an item");
        return;
      }

      const qty = parseFloat(form.quantity);
      const price = parseFloat(form.rate);

      if (!qty || qty <= 0) {
        showApiError("Please enter a valid quantity greater than 0");
        return;
      }

      if (!price || price <= 0) {
        showApiError("Please enter a valid price greater than 0");
        return;
      }

      const payload = {
        items: [
          {
            item_code: form.id,
            qty: qty,
            price: price,
          },
        ],
      };

      showLoading("Creating Stock Entry...");

      setLoading(true);

      const res = await createItemStock(payload);

      if (!res || ![200, 201].includes(res.status_code)) {
        closeSwal();
        showApiError(res);
        return;
      }

      closeSwal();
      showSuccess("Stock entry created successfully");

      onSubmit?.();
      handleClose();
    } catch (error: any) {
      closeSwal();
      showApiError(error);
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setForm(emptyForm);
    onClose();
  };

  const handleForm = (
    e: React.ChangeEvent<
      HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement
    >,
  ) => {
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const reset = () => {
    setForm(emptyForm);
  };

  if (!isOpen) return null;

  return (
    <Modal
      isOpen={isOpen}
      onClose={handleClose}
      title={isEditMode ? "Edit Stock Entry" : "Add Stock Entry"}
      subtitle="Create and manage stock entry details"
      maxWidth="4xl"
      height="70vh"
    >
      <form onSubmit={handleSubmit} className="h-full flex flex-col">
        {/* Tabs */}
        <div className="flex bg-gray-50">
          <button
            type="button"
            onClick={() => setActiveTab("details")}
            className={`flex items-center gap-2 px-6 py-3 text-sm font-medium transition-colors ${
              activeTab === "details"
                ? "text-indigo-600 bg-white"
                : "text-gray-600 hover:text-gray-900"
            }`}
          >
            Stock Entry Details
          </button>
        </div>

        {/* Tab Content */}
        <section className="flex-1 overflow-y-auto p-3 space-y-4">
          <div className="max-h-screen overflow-auto p-3">
            {activeTab === "details" && (
              <>
                <div className="bg-card border border-theme rounded-xl p-4">
                  <div className="flex items-center justify-between mb-4">
                    <div>
                      <div className="text-xs font-bold text-main uppercase tracking-wide">
                        Stock Information
                      </div>
                      <div className="text-xs text-muted mt-1">
                        Select an item and enter quantity and price
                      </div>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div className="flex flex-col gap-1 text-sm col-span-1">
                      <SearchSelect
                        label="Select Item"
                        value={form.itemName}
                        placeholder="Type to search items..."
                        required
                        fetchOptions={async (q: string) => {
                          const query = (q || "").toLowerCase();
                          return itemOptions
                            .filter((item) =>
                              item.label.toLowerCase().includes(query),
                            )
                            .slice(0, 50)
                            .map((item) => ({
                              label: item.label,
                              value: item.id,
                            }));
                        }}
                        onChange={(selectedId: string) => {
                          if (!selectedId) {
                            setForm((prev) => ({
                              ...prev,
                              id: "",
                              itemClassCode: "",
                            }));
                            return;
                          }

                          const selectedItem = itemOptions.find(
                            (item) => item.id === selectedId,
                          );

                          setForm((prev) => ({
                            ...prev,
                            id: selectedId,
                            itemName: selectedItem?.label || "",
                            itemClassCode: selectedItem?.itemClassCode || "",
                          }));
                        }}
                      />
                    </div>

                    <Input
                      label="Item Code"
                      name="itemClassCode"
                      value={form.itemClassCode || ""}
                      onChange={handleForm}
                      placeholder="Auto-filled after selecting item"
                      className="w-full"
                      readOnly
                    />

                    <Input
                      label="Item Name"
                      name="itemName"
                      value={form.itemName || ""}
                      onChange={handleForm}
                      placeholder="Auto-filled after selecting item"
                      className="w-full"
                      readOnly
                    />

                    <Input
                      label="Item Quantity"
                      name="quantity"
                      type="number"
                      step="1"
                      value={form.quantity || ""}
                      onChange={handleForm}
                      placeholder="e.g. 10"
                      className="w-full"
                      required
                    />

                    <Input
                      label="Item Price"
                      name="rate"
                      type="number"
                      step="0.01"
                      value={form.rate || ""}
                      onChange={handleForm}
                      placeholder="e.g. 25.00"
                      className="w-full"
                      required
                    />
                  </div>
                </div>
              </>
            )}
          </div>
        </section>
        {/* FOOTER INSIDE FORM */}
        <div className="flex justify-end gap-2 px-6 py-4">
          <Button
            variant="secondary"
            type="button"
            onClick={handleClose}
            disabled={loading}
          >
            Cancel
          </Button>

          <Button
            variant="ghost"
            type="button"
            onClick={reset}
            disabled={loading}
          >
            Reset
          </Button>

          <Button variant="primary" loading={loading} type="submit">
            Save Stock Entry
          </Button>
        </div>
      </form>
    </Modal>
  );
};

// Input component
const Input = React.forwardRef<
  HTMLInputElement,
  React.InputHTMLAttributes<HTMLInputElement> & { label: string }
>(({ label, className = "", ...props }, ref) => (
  <label className="flex flex-col gap-1 text-sm w-full">
    <span className="font-medium text-gray-600">{label}</span>
    <input
      ref={ref}
      className={`rounded border px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-400 ${
        props.disabled ? "bg-gray-100 text-gray-500 cursor-not-allowed" : ""
      } ${className}`}
      {...props}
    />
  </label>
));
Input.displayName = "Input";

export default ItemModal;

import React, { useState } from "react";
import { Plus, Trash2 } from "lucide-react";
import { FileText } from "lucide-react";
import TermsAndCondition from "../TermsAndCondition";
import { User, Mail, Phone } from "lucide-react";
import CustomerSelect from "../selects/CustomerSelect";
import Modal from "../../components/ui/modal/modal";
import { Button } from "../../components/ui/modal/formComponent";
import { ModalInput, ModalSelect } from "../ui/modal/modalComponent";
import ItemSelect from "../selects/ItemSelect";
import { useInvoiceForm } from "../../hooks/useInvoiceForm";
import CountrySelect from "../selects/CountrySelect";
import {
  currencySymbols,
  paymentMethodOptions,
  currencyOptions,
} from "../../constants/invoice.constants";
import PaymentInfoBlock from "./PaymentInfoBlock";
import AddressBlock from "../ui/modal/AddressBlock";
import { showApiError } from "../../utils/alert";

// import ModalInput from "../ui/ModalInput";
// import ModalSelect from "../ui/ModalSelect";

interface InvoiceModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit?: (data: any) => void;
}

const InvoiceModal: React.FC<InvoiceModalProps> = ({
  isOpen,
  onClose,
  onSubmit,
}) => {
  if (!isOpen) return null;
  const [submitting, setSubmitting] = useState(false);
  const {
    formData,
    customerDetails,
    customerNameDisplay,
    paginatedItems,
    totals,
    ui,
    actions,
  } = useInvoiceForm(isOpen, onClose, onSubmit);

  const symbol = currencySymbols[formData.currencyCode] ?? "ZK";
  const currencyCode = String(formData.currencyCode ?? "")
    .trim()
    .toUpperCase();
  const showExchangeRate = !!currencyCode && currencyCode !== "ZMW";
  const handleFormSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (submitting) return;

    try {
      setSubmitting(true);
      const payload = await actions.handleSubmit(e);

      if (!payload) return;

      // ❗ Wait for parent API response
      await onSubmit?.(payload);
    } catch (err: any) {
      showApiError(err);
    } finally {
      setSubmitting(false);
    }
  };

  const footerContent = (
    <>
      <Button
        variant="secondary"
        onClick={onClose}
        type="button"
        disabled={submitting}
      >
        Cancel
      </Button>
      <div className="flex gap-2">
        <Button
          variant="ghost"
          onClick={actions.handleReset}
          type="button"
          disabled={submitting}
        >
          Reset
        </Button>
        <Button
          variant="primary"
          type="submit"
          onClick={handleFormSubmit}
          loading={submitting}
        >
          {submitting ? "Submitting..." : "Submit"}
        </Button>
      </div>
    </>
  );

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      title="Create Invoice"
      subtitle="Create and manage invoice details"
      icon={FileText}
      footer={footerContent}
      maxWidth="wide"
      height="79vh"
    >
      <form
        onSubmit={handleFormSubmit}
        className="h-full flex flex-col min-w-0"
      >
        {/* Tabs */}
        <div className="bg-app border-b border-theme px-8 shrink-0">
          <div className="flex gap-8">
            {(["details", "address", "terms"] as const).map((tab) => (
              <button
                key={tab}
                type="button"
                onClick={() => ui.setActiveTab(tab)}
                className={`py-2.5 bg-transparent border-none text-xs font-medium cursor-pointer transition-all 
              ${
                ui.activeTab === tab
                  ? "text-primary border-b-[3px] border-primary"
                  : "text-muted border-b-[3px] border-transparent hover:text-main"
              }`}
              >
                {tab === "details" && "Details"}
                {tab === "address" && "Additional Details"}
                {tab === "terms" && "Terms & Conditions"}
              </button>
            ))}
          </div>
        </div>

        {/* Tab Content */}
        <div className="flex-1 overflow-y-auto overflow-x-hidden px-8 py-4 min-w-0 ">
          {/* DETAILS */}
          {ui.activeTab === "details" && (
            <div className="flex flex-col gap-6 max-w-[1600px] mx-auto">
              <div className="">
                <div
                  className={`grid ${showExchangeRate ? "grid-cols-6" : "grid-cols-5"} gap-3 items-end`}
                >
                  <CustomerSelect
                    value={customerNameDisplay}
                    onChange={actions.handleCustomerSelect}
                    className="w-full"
                  />

                  <div>
                    <ModalInput
                      label="Due Date"
                      name="dueDate"
                      type="date"
                      value={formData.dueDate}
                      onChange={actions.handleInputChange}
                      className="w-full py-1 px-2 border border-theme rounded text-[11px] text-main bg-card"
                    />
                  </div>

                  <div>
                    <ModalSelect
                      label="Currency"
                      required
                      name="currencyCode"
                      value={formData.currencyCode}
                      onChange={actions.handleInputChange}
                      options={[...currencyOptions]}
                      className="w-full py-1 px-2 border border-theme rounded text-[11px] text-main bg-card"
                    />
                  </div>

                  {showExchangeRate && (
                    <div>
                      <ModalInput
                        label={
                          ui.exchangeRateLoading
                            ? "Exchange Rate (Loading...)"
                            : "Exchange Rate"
                        }
                        name="exchangeRt"
                        value={formData.exchangeRt}
                        onChange={actions.handleInputChange}
                        className="w-full py-1 px-2 border border-theme rounded text-[11px] text-main bg-card"
                      />
                      {!!ui.exchangeRateError && (
                        <div className="mt-1 text-[10px] text-danger">
                          {ui.exchangeRateError}
                        </div>
                      )}
                    </div>
                  )}

                  <div>
                    <ModalSelect
                      label="Payment Method"
                      required
                      name="paymentMethod"
                      value={formData.paymentInformation?.paymentMethod || ""}
                      onChange={(
                        e: React.ChangeEvent<
                          HTMLInputElement | HTMLSelectElement
                        >,
                      ) => actions.handleInputChange(e, "paymentInformation")}
                      options={[...paymentMethodOptions]}
                      className="w-full py-1 px-2 border border-theme rounded text-[11px] text-main bg-card"
                    />
                  </div>

                  {/* <div>
                    <ModalInput
                      label="Invoice Type"
                      name="invoiceType"
                      type="text"
                      disabled
                      value={formData.invoiceType}
                      onChange={actions.handleInputChange}
                     className="w-full py-1 px-2 border border-theme rounded text-[11px] text-main bg-card"
                    />
                  </div> */}

                  {(ui.isExport || ui.hasC1) && (
                    <CountrySelect
                      value={formData.destnCountryCd}
                      required
                      onChange={(c) =>
                        actions.handleInputChange({
                          target: {
                            name: "destnCountryCd",
                            value: c.code,
                          },
                        } as any)
                      }
                    />
                  )}

                  {ui.isLocal && (
                    <ModalInput
                      label="LPO Number"
                      name="lpoNumber"
                      value={formData.lpoNumber}
                      onChange={actions.handleInputChange}
                      inputMode="numeric"
                      pattern="\d{10}"
                      placeholder="Enter 10 digits"
                      className="w-full py-1 px-2 border border-theme rounded text-[11px] text-main bg-card"
                    />
                  )}
                </div>
              </div>

              {/* ITEMS */}
              <div className="grid grid-cols-1 lg:grid-cols-[4fr_1fr] gap-4 min-w-0">
                <div className="bg-card rounded-lg p-2 shadow-sm flex-1 min-w-0">
                  <div className="flex items-center gap-1 ">
                    <h3 className="text-sm font-semibold text-main">
                      Invoiced Items
                    </h3>
                  </div>

                  <div className="mt-2 overflow-x-hidden">
                    <table className="w-full border-collapse table-fixed text-[10px]">
                      <thead>
                        <tr className="border-b border-theme">
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[25px] whitespace-nowrap">
                            #
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[120px] whitespace-nowrap">
                            Item
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[120px] whitespace-nowrap hidden xl:table-cell">
                            Description
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[50px] whitespace-nowrap">
                            Quantity
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[80px] md:w-[90px] whitespace-nowrap">
                            Unit Price
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[70px] md:w-[80px] whitespace-nowrap">
                            Discount (%)
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[50px] whitespace-nowrap">
                            Tax
                          </th>
                          <th className="px-2 py-3 text-left text-muted font-medium text-[11px] w-[60px] md:w-[70px] whitespace-nowrap hidden lg:table-cell">
                            Tax Code
                          </th>
                          <th className="px-2 py-3 text-right text-muted font-medium text-[11px] w-[90px] md:w-[100px] whitespace-nowrap">
                            Amount
                          </th>
                          <th className="px-2 py-3 text-center text-muted font-medium text-[11px] w-[42px] whitespace-nowrap"></th>
                        </tr>
                      </thead>
                      <tbody>
                        {paginatedItems.map((it, idx) => {
                          const i = ui.page * 5 + idx;
                          const discountAmount =
                            it.quantity *
                            it.price *
                            (Number(it.discount || 0) / 100);
                          const amount =
                            it.quantity * it.price - discountAmount;

                          return (
                            <tr
                              key={i}
                              className="border-b border-theme bg-card row-hover"
                            >
                              <td className="px-3 py-2 text-center">{i + 1}</td>
                              <td className="px-0.5 py-1 min-w-0">
                                {/* <ItemSelect
                                    taxCategory={ui.taxCategory}
                                    value={it.itemCode}
                                    onChange={(item) => {
                                      actions.updateItemDirectly(i, {
                                        itemCode: item.id,
                                        price: item.sellingPrice ?? it.price,
                                      });
                                    }}
                                  /> */}
                                <ItemSelect
                                  taxCategory={ui.taxCategory}
                                  value={it.itemCode}
                                  excludeItemCodes={formData.items
                                    .map((x, j) => (j === i ? "" : x?.itemCode))
                                    .filter(Boolean)}
                                  onChange={(item) => {
                                    actions.handleItemSelect(i, item.id);
                                  }}
                                />
                              </td>

                              <td className="px-0.5 py-1 hidden xl:table-cell">
                                <input
                                  className="w-full py-1 px-2 border border-theme rounded text-[10px] bg-card text-main focus:outline-none focus:ring-1 focus:ring-primary"
                                  name="description"
                                  value={it.description}
                                  onChange={(e) =>
                                    actions.handleItemChange(i, e)
                                  }
                                />
                              </td>
                              <td className="px-0.5 py-1">
                                <input
                                  type="number"
                                  className="w-[50px] py-1 px-2 border border-theme rounded text-[11px] bg-card text-main focus:outline-none focus:ring-1 focus:ring-primary"
                                  name="quantity"
                                  value={it.quantity}
                                  onChange={(e) =>
                                    actions.handleItemChange(i, e)
                                  }
                                />
                              </td>
                              <td className="px-0.5 py-1">
                                <input
                                  type="number"
                                  className="w-[80px] md:w-[90px] py-1 px-2 border border-theme rounded text-[11px] bg-card text-main focus:outline-none focus:ring-1 focus:ring-primary"
                                  name="price"
                                  value={it.price}
                                  disabled
                                  onChange={(e) =>
                                    actions.handleItemChange(i, e)
                                  }
                                />
                              </td>
                              <td className="px-0.5 py-1">
                                <input
                                  type="number"
                                  className="w-[70px] md:w-[80px] py-1 px-2 border border-theme rounded text-[11px] bg-card text-main focus:outline-none focus:ring-1 focus:ring-primary"
                                  name="discount"
                                  value={it.discount}
                                  onChange={(e) =>
                                    actions.handleItemChange(i, e)
                                  }
                                />
                              </td>
                              <td className="px-0.5 py-1">
                                <input
                                  type="number" // Assuming input is number for entry, stored as string in Type
                                  className="w-[50px] py-1 px-2 border border-theme rounded text-[11px] bg-card text-main focus:outline-none focus:ring-1 focus:ring-primary"
                                  name="vatRate"
                                  value={it.vatRate}
                                  disabled
                                  onChange={(e) =>
                                    actions.handleItemChange(i, e)
                                  }
                                />
                              </td>
                              <td className="px-0.5 py-1 hidden lg:table-cell">
                                <input
                                  type="string"
                                  className="w-[60px] md:w-[70px] py-1 px-2 border border-theme rounded text-[11px] bg-card text-main focus:outline-none focus:ring-1 focus:ring-primary"
                                  name="vatCode"
                                  value={it.vatCode}
                                  disabled
                                  onChange={(e) =>
                                    actions.handleItemChange(i, e)
                                  }
                                />
                              </td>
                              <td className="px-2 py-2 text-right font-semibold text-gray-900 whitespace-nowrap">
                                {symbol} {amount.toFixed(2)}
                              </td>

                              <td className="px-1 py-1 text-center">
                                <button
                                  type="button"
                                  onClick={() => actions.removeItem(i)}
                                  className="p-0.5 rounded bg-danger/10 text-danger hover:bg-danger/20 transition text-[10px]"
                                  title="Remove item"
                                >
                                  <Trash2 className="w-4 h-4" />
                                </button>
                              </td>
                            </tr>
                          );
                        })}
                      </tbody>
                    </table>
                  </div>

                  <style>{`
                    .hide-scrollbar::-webkit-scrollbar { display:none }
                    .hide-scrollbar { scrollbar-width:none; -ms-overflow-style:none }
                  `}</style>

                  <div className="flex justify-between mt-3">
                    <button
                      type="button"
                      onClick={actions.addItem}
                      className="px-4 py-1.5 bg-primary hover:bg-[var(--primary-600)] text-white rounded text-xs font-medium flex items-center gap-1.5 transition-colors"
                    >
