                    >
                      <stop
                        offset="5%"
                        stopColor="#2563eb"
                        stopOpacity={0.35}
                      />
                      <stop
                        offset="95%"
                        stopColor="#2563eb"
                        stopOpacity={0.04}
                      />
                    </linearGradient>
                  </defs>
                  <CartesianGrid
                    strokeDasharray="3 3"
                    stroke="rgba(148,163,184,0.35)"
                  />
                  <XAxis
                    dataKey="name"
                    tick={{ fill: "rgba(100,116,139,1)", fontSize: 12 }}
                    axisLine={{ stroke: "rgba(148,163,184,0.5)" }}
                    tickLine={{ stroke: "rgba(148,163,184,0.5)" }}
                  />
                  <YAxis
                    tick={{ fill: "rgba(100,116,139,1)", fontSize: 12 }}
