    sortBy: colKey,
    sortOrder: order,
  }: {
    sortBy: string;
    sortOrder: "asc" | "desc";
  }) => {
    setSortBy(colKey); // store column key, not a backend alias
    setSortOrder(order);
    setPage(1);
  };

  const fetchAllInvoicesForExport = async (): Promise<InvoiceSummary[]> => {
    try {
      let allData: InvoiceSummary[] = [];
      let current = 1;
      let total = 1;

      do {
        const res = await getAllSalesInvoices(
          current,
          100,
          sortBy,
          sortOrder,
          searchTerm,
