              totalTax: inv.totalTax,
              invoiceTypeParent: inv.invoiceTypeParent,
              invoiceType: inv.invoiceType,
            };
          });

          allData = [...allData, ...mapped];
          total = res.pagination?.total_pages || 1;
        }

        current++;
      } while (current <= total);

      allData.sort(
        (a, b) =>
          (b.invoiceDateTime?.getTime() ?? 0) -
          (a.invoiceDateTime?.getTime() ?? 0),
      );

      return allData;
    } catch (error) {
      showApiError(error);
      return [];
    }
