      align: "right",
      sortable: true,
      render: (inv) => (
        <code className="text-xs px-2 py-1 rounded bg-row-hover text-main font-semibold whitespace-nowrap">
          {inv.total.toLocaleString()} {inv.currency}
        </code>
      ),
    },
    {
      key: "actions",
      header: "Actions",
      align: "center",
      render: (inv) => (
        <ActionGroup>
          <ActionButton
            type="view"
            onClick={(e) => handleViewClick(inv.invoiceNumber, e)}
            iconOnly
          />
          <ActionMenu
            onDelete={(e) => handleDelete(inv.invoiceNumber, e)}
            showDownload
            onDownload={(e) => handleDownload(inv, e)}
          />
        </ActionGroup>
      ),
    },
  ];

  return (
    <div className="p-8">
      <Table
        columns={columns}
        data={invoices} // ← raw server data, no local filter
        rowKey={(row) => row.invoiceNumber}
        loading={loading || initialLoad}
        showToolbar
        searchValue={searchTerm}
        onSearch={(q) => {
          setSearchTerm(q);
          setPage(1);
        }}
        enableAdd
        addLabel="Add Invoice"
        onAdd={onAddInvoice}
        enableColumnSelector
        enableExport
        onExport={onExportInvoice ?? handleExportExcel}
        currentPage={page}
        totalPages={totalPages}
        pageSize={pageSize}
        totalItems={totalItems}
        pageSizeOptions={[10, 25, 50, 100]}
        onPageSizeChange={(size) => {
          setPageSize(size);
          setPage(1);
        }}
        onPageChange={setPage}
        sortBy={sortBy}
        sortOrder={sortOrder}
        onSortChange={handleSortChange}
      />

      {/* PDF Preview modal — kept, used by handleClosePdf */}
      <PdfPreviewModal
        open={pdfOpen}
        title="Invoice Preview"
        pdfUrl={pdfUrl}
        onClose={handleClosePdf}
        onDownload={() =>
          selectedInvoice &&
          company &&
          generateInvoicePDF(selectedInvoice, company, "save")
        }
      />

      <InvoiceDetailsModal
        open={invoiceDetailsOpen}
        invoiceId={invoiceDetailsId}
        onClose={handleCloseInvoiceDetails}
        onOpenReceiptPdf={handleOpenReceiptPdf}
      />
    </div>
  );
};

export default InvoiceTable;

import React, { useEffect, useState } from "react";
import {
  getAllProformaInvoices,
  getProformaInvoiceById,
  deleteProformaInvoiceById,
} from "../../api/proformaInvoiceApi";
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";
import { getCompanyById } from "../../api/companySetupApi";
const COMPANY_ID = import.meta.env.VITE_COMPANY_ID;
import type { ProformaInvoiceSummary } from "../../types/proformaInvoice";
import { generateProformaInvoicePDF } from "../../components/template/proformatemplete/ProformaInvoiceTemplate";
import Table from "../../components/ui/Table/Table";
import ActionButton, {
  ActionGroup,
  ActionMenu,
} from "../../components/ui/Table/ActionButton";
import type { Column } from "../../components/ui/Table/type";
import {
  showApiError,
  showSuccess,
  showLoading,
  closeSwal,
} from "../../utils/alert";
import Swal from "sweetalert2";
import InvoiceDetailsModal, {
  type InvoiceDetails,
} from "./InvoiceDetailsModal";

// Column key → backend field mapping
// All keys are identical here so the map is 1:1,
// but keeping it explicit makes future changes safe
const SORT_FIELD_MAP: Record<string, string> = {
  proformaId: "proformaId",
  customerName: "customerName",
  createdAt: "createdAt",
  dueDate: "dueDate",
  totalAmount: "totalAmount",
};

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

interface ProformaInvoiceTableProps {
  onAddProformaInvoice?: () => void;
  onExportProformaInvoice?: () => void;
  refreshKey: number;
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

const ProformaInvoicesTable: React.FC<ProformaInvoiceTableProps> = ({
  onAddProformaInvoice,
  refreshKey,
}) => {
  // ── Data ──────────────────────────────────────────────────────────────────
  const [invoices, setInvoices] = useState<ProformaInvoiceSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [initialLoad, setInitialLoad] = useState(true);
  const [company, setCompany] = useState<any>(null);

  // ── Pagination (server) ───────────────────────────────────────────────────
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  // ── Search (server) ───────────────────────────────────────────────────────
  const [searchTerm, setSearchTerm] = useState("");

  // ── Sort (server) — always store column key, map to backend at call site ──
  const [sortBy, setSortBy] = useState("");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");

  // ── Modal ─────────────────────────────────────────────────────────────────
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [detailsId, setDetailsId] = useState<string | null>(null);

  // ── Reset page when search changes ───────────────────────────────────────
  useEffect(() => {
    setPage(1);
  }, [searchTerm]);

  // ── Fetch company once ────────────────────────────────────────────────────
  useEffect(() => {
    getCompanyById(COMPANY_ID)
      .then((res) => {
        if (res?.status_code === 200) setCompany(res.data);
      })
      .catch(() => console.error("Failed to load company data"));
  }, []);

  // ── Fetch invoices ────────────────────────────────────────────────────────
  const fetchInvoices = async () => {
    try {
      setLoading(true);

      // NOTE: add `search` param to getAllProformaInvoices in proformaInvoiceApi.ts
      // signature: getAllProformaInvoices(page, page_size, sortBy, sortOrder, search)
      const res = await getAllProformaInvoices(
        page,
        pageSize,
        SORT_FIELD_MAP[sortBy] || sortBy, // ← map column key → backend field here
        sortOrder,
        searchTerm, // ← search sent to backend
      );

      if (!res || res.status_code !== 200) return;

      const mapped: ProformaInvoiceSummary[] = res.data.map((inv: any) => ({
        proformaId: inv.proformaId,
        customerName: inv.customerName,
        currency: inv.currency,
        exchangeRate: inv.exchangeRate,
        dueDate: inv.dueDate,
        totalAmount: Number(inv.totalAmount),
        createdAt: new Date(inv.createdAt.replace(" ", "T")),
      }));

      setInvoices(mapped);
      setTotalPages(res.pagination?.total_pages || 1);
      setTotalItems(res.pagination?.total || mapped.length);
    } finally {
      setLoading(false);
      setInitialLoad(false);
    }
  };

  useEffect(() => {
    fetchInvoices();
  }, [page, pageSize, refreshKey, sortBy, sortOrder, searchTerm]); // ← searchTerm included

  // ── Sort handler — store column key, translate at API call site ───────────
  const handleSortChange = ({
    sortBy: colKey,
    sortOrder: order,
  }: {
    sortBy: string;
    sortOrder: "asc" | "desc";
  }) => {
    setSortBy(colKey); // ← store "proformaId", not "proformaId" (same here, but correct pattern)
    setSortOrder(order);
    setPage(1);
  };

  // ── Receipt URL opener (kept — do not remove) ─────────────────────────────
  const handleOpenReceipt = (receiptUrl: string) => {
    const normalizedUrl = receiptUrl.startsWith("http://")
      ? receiptUrl.replace(/^http:\/\//i, "https://")
      : receiptUrl;

    const urlWithoutPort = (() => {
      try {
        const u = new URL(normalizedUrl);
        u.port = "";
        return u.toString();
      } catch {
        return normalizedUrl.replace(
          /^(https?:\/\/[^\/]+):\d+(\/.*)?$/i,
          "$1$2",
        );
      }
    })();

    const a = document.createElement("a");
    a.href = urlWithoutPort;
    a.target = "_blank";
    a.rel = "noopener noreferrer";
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

  // ── Export all pages ──────────────────────────────────────────────────────
  const fetchAllInvoicesForExport = async (): Promise<
    ProformaInvoiceSummary[]
  > => {
    try {
      let allData: ProformaInvoiceSummary[] = [];
      let current = 1;
      let total = 1;

      do {
        const res = await getAllProformaInvoices(
          current,
          100,
          SORT_FIELD_MAP[sortBy] || sortBy, // ← same mapping for export
          sortOrder,
          searchTerm,
        );

        if (res?.status_code === 200) {
          const mapped = res.data.map((inv: any) => ({
            proformaId: inv.proformaId,
            customerName: inv.customerName,
            currency: inv.currency,
            exchangeRate: inv.exchangeRate,
            dueDate: inv.dueDate,
            totalAmount: Number(inv.totalAmount),
            createdAt: new Date(inv.createdAt.replace(" ", "T")),
          }));

          allData = [...allData, ...mapped];
          total = res.pagination?.total_pages || 1;
        }

        current++;
      } while (current <= total);

      return allData;
    } catch (error) {
      showApiError(error);
      return [];
    }
  };

  const handleExportExcel = async () => {
    try {
      showLoading("Exporting Proforma Invoices...");

      const dataToExport = await fetchAllInvoicesForExport();

      if (!dataToExport.length) {
        closeSwal();
        showApiError("No invoices to export");
        return;
      }

      const worksheet = XLSX.utils.json_to_sheet(
        dataToExport.map((inv) => ({
          "Proforma No": inv.proformaId,
          Customer: inv.customerName,
          Date: inv.createdAt.toLocaleDateString(),
          "Due Date": inv.dueDate
            ? new Date(inv.dueDate).toLocaleDateString()
            : "",
          Amount: inv.totalAmount,
          Currency: inv.currency,
        })),
      );

      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Proforma Invoices");

      saveAs(
        new Blob([XLSX.write(workbook, { bookType: "xlsx", type: "array" })], {
          type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        }),
        "Proforma_Invoices.xlsx",
      );

      closeSwal();
      showSuccess("Export completed successfully");
    } catch (error) {
      closeSwal();
      showApiError(error);
    }
  };

  // ── Actions ───────────────────────────────────────────────────────────────

  const handleView = (proformaId: string, e?: React.MouseEvent) => {
    e?.stopPropagation();
    setDetailsId(proformaId);
    setDetailsOpen(true);
  };

  const handleDownload = async (proformaId: string, e?: React.MouseEvent) => {
    e?.stopPropagation();
    try {
      showLoading("Preparing proforma invoice download...");

      if (!company) {
        closeSwal();
        console.error("Company data not loaded");
        return;
      }

      const res = await getProformaInvoiceById(proformaId);
      if (!res || res.status_code !== 200) {
        closeSwal();
        showApiError("Failed to load invoice");
        return;
      }

      await generateProformaInvoicePDF(res.data, company, "save");
      closeSwal();
      showSuccess("Proforma invoice downloaded");
    } catch (err: any) {
      closeSwal();
      showApiError(err);
    }
  };

  const handleDelete = async (proformaId: string, e?: React.MouseEvent) => {
    e?.stopPropagation();

    const result = await Swal.fire({
      icon: "warning",
      title: "Are you sure?",
      text: `Delete proforma invoice ${proformaId}?`,
      showCancelButton: true,
      confirmButtonColor: "#ef4444",
      cancelButtonColor: "#6b7280",
      confirmButtonText: "Yes, delete",
    });

    if (!result.isConfirmed) return;

    try {
      Swal.fire({
        title: "Deleting...",
        text: "Please wait while we delete the invoice.",
        allowOutsideClick: false,
        allowEscapeKey: false,
        showConfirmButton: false,
        didOpen: () => Swal.showLoading(),
      });

      const res = await deleteProformaInvoiceById(proformaId);
      Swal.close();

      if (!res || res.status_code !== 200) {
        showApiError(res?.message || "Delete failed");
        return;
      }

      setInvoices((prev) =>
        prev.filter((inv) => inv.proformaId !== proformaId),
      );
      showSuccess("Proforma invoice deleted successfully");
    } catch (err) {
      Swal.close();
      showApiError(err);
    }
  };

  const mapProformaToInvoiceDetails = (raw: any): InvoiceDetails => {
    const items = Array.isArray(raw?.items)
      ? raw.items.map((it: any) => ({
          itemCode: it?.itemCode,
          itemName: it?.itemName,
          quantity: Number(it?.quantity ?? 0),
          description: it?.description,
          discount: Number(it?.discount ?? 0),
          price: Number(it?.price ?? 0),
          vatCode: it?.vatCode ?? it?.tax,
          vatTaxableAmount: it?.vatTaxableAmount ?? it?.itemTotal,
        }))
      : [];

    return {
      invoiceNumber: raw?.proformaId,
      invoiceType: raw?.invoiceType ?? "Proforma",
      customerName: raw?.customerName,
      customerTpin: raw?.customerTpin,
      currencyCode: raw?.currencyCode,
      exchangeRt: raw?.exchangeRt,
      dateOfInvoice: raw?.dateOfInvoice ?? raw?.dateofinvoice,
      dueDate: raw?.dueDate,
      discountPercentage:
        raw?.discountPercentage !== undefined &&
        raw?.discountPercentage !== null
          ? Number(raw.discountPercentage)
          : undefined,
      discountAmount:
        raw?.discountAmount !== undefined && raw?.discountAmount !== null
          ? Number(raw.discountAmount)
          : undefined,
      Receipt: raw?.Receipt ?? raw?.receipt,
      ReceiptNo: raw?.ReceiptNo ?? raw?.receiptNo,
      TotalAmount: raw?.TotalAmount ?? raw?.totalAmount,
      billingAddress: raw?.billingAddress,
      shippingAddress: raw?.shippingAddress,
      paymentInformation: raw?.paymentInformation,
      items,
      terms: raw?.terms,
    };
  };

  const columns: Column<ProformaInvoiceSummary>[] = [
    {
      key: "proformaId",
      header: "Proforma No",
      align: "left",
      sortable: true,
      render: (inv) => (
        <span className="font-semibold text-main">{inv.proformaId}</span>
      ),
    },
    {
      key: "customerName",
      header: "Customer",
      align: "left",
      sortable: true,
      render: (inv) => (
        <span className="text-sm text-main">{inv.customerName}</span>
      ),
    },
    {
      key: "createdAt",
      header: "Date",
      align: "left",
      sortable: true,
      render: (inv) => (
        <span className="text-xs text-muted">
          {inv.createdAt.toLocaleDateString()}
        </span>
      ),
    },
    {
      key: "dueDate",
      header: "Due Date",
      align: "left",
      sortable: true,
      render: (inv) => (
        <span className="text-xs text-muted">
          {inv.dueDate ? new Date(inv.dueDate).toLocaleDateString() : "—"}
        </span>
      ),
    },
    {
      key: "totalAmount",
      header: "Amount",
      align: "right",
      sortable: true,
      render: (inv) => (
        <code className="text-xs px-2 py-1 rounded bg-row-hover text-main">
          {inv.currency} {inv.totalAmount.toLocaleString()}
        </code>
      ),
    },
    {
      key: "actions",
      header: "Actions",
      align: "center",
      render: (inv) => (
        <ActionGroup>
          <ActionButton
            type="view"
            onClick={(e) => handleView(inv.proformaId, e)}
            iconOnly
          />
          <ActionMenu
            showDownload
            onDownload={(e) => handleDownload(inv.proformaId, e)}
            onDelete={(e) => handleDelete(inv.proformaId, e)}
          />
        </ActionGroup>
      ),
    },
  ];

  // ── Render ────────────────────────────────────────────────────────────────

  return (
    <div className="p-8">
      <Table
        loading={loading || initialLoad}
        columns={columns}
        data={invoices}
        rowKey={(row) => row.proformaId}
        showToolbar
        searchValue={searchTerm}
        onSearch={(q) => {
          setSearchTerm(q);
          setPage(1);
        }}
        enableAdd
        addLabel="Add Proforma Invoice"
        onAdd={onAddProformaInvoice}
        enableExport
        onExport={handleExportExcel}
        enableColumnSelector
        currentPage={page}
        totalPages={totalPages}
        pageSize={pageSize}
        totalItems={totalItems}
        pageSizeOptions={[10, 25, 50, 100]}
        onPageSizeChange={(size) => {
          setPageSize(size);
          setPage(1);
        }}
        onPageChange={setPage}
        sortBy={sortBy}
        sortOrder={sortOrder}
        onSortChange={handleSortChange}
      />

      <InvoiceDetailsModal
        open={detailsOpen}
        invoiceId={detailsId}
        onClose={() => {
          setDetailsOpen(false);
          setDetailsId(null);
        }}
        onOpenReceiptPdf={handleOpenReceipt}
        fetchDetails={getProformaInvoiceById}
        mapDetails={mapProformaToInvoiceDetails}
      />
    </div>
  );
};

export default ProformaInvoicesTable;

import React, { useEffect, useState } from "react";
import {
  showApiError,
  showSuccess,
  showLoading,
  closeSwal,
} from "../../utils/alert";
import { getAllQuotations, getQuotationById } from "../../api/quotationApi";
import { getCompanyById } from "../../api/companySetupApi";
import type { QuotationSummary } from "../../types/quotation";
import Table from "../../components/ui/Table/Table";
import ActionButton, {
  ActionGroup,
  ActionMenu,
} from "../../components/ui/Table/ActionButton";
import InvoiceDetailsModal, {
  type InvoiceDetails,
} from "./InvoiceDetailsModal";
import type { Column } from "../../components/ui/Table/type";
import * as XLSX from "xlsx";
import { saveAs } from "file-saver";
import { generateQuotationPDF } from "../../components/template/quotation/QuotationTemplate1";

const COMPANY_ID = import.meta.env.VITE_COMPANY_ID;

const SORT_FIELD_MAP: Record<string, string> = {
  quotationNumber: "id",
  customerName: "customerName",
  transactionDate: "transactionDate",
  validTill: "validTill",
  grandTotal: "grandTotal",
};

interface QuotationTableProps {
  onAddQuotation?: () => void;
  onExportQuotation?: () => void;
}

const QuotationsTable: React.FC<QuotationTableProps> = ({ onAddQuotation }) => {
  const [quotations, setQuotations] = useState<QuotationSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [initialLoad, setInitialLoad] = useState(true);
  const [company, setCompany] = useState<any>(null);

  // ── Pagination state (server) ────────────────────────────────────────────
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(10);
  const [totalPages, setTotalPages] = useState(1);
  const [totalItems, setTotalItems] = useState(0);

  // ── Search state (server) ────────────────────────────────────────────────
  const [searchTerm, setSearchTerm] = useState("");

  // ── Sort state (server) — always store column key, not backend field ─────
  const [sortBy, setSortBy] = useState("");
  const [sortOrder, setSortOrder] = useState<"asc" | "desc">("desc");

  // ── Filter state (server) ────────────────────────────────────────────────
  const [fromDate] = useState("");
  const [toDate] = useState("");

  // ── Modal state ──────────────────────────────────────────────────────────
  const [detailsOpen, setDetailsOpen] = useState(false);
  const [detailsId, setDetailsId] = useState<string | null>(null);

  // ── Reset page when search changes ──────────────────────────────────────
  useEffect(() => {
    setPage(1);
  }, [searchTerm]);

  // ── Fetch company once ───────────────────────────────────────────────────
  useEffect(() => {
    getCompanyById(COMPANY_ID)
      .then((res) => {
        if (res?.status_code === 200) setCompany(res.data);
      })
      .catch(() => console.error("Failed to load company data"));
  }, []);

  const fetchQuotations = async () => {
    try {
      setLoading(true);

      const res = await getAllQuotations(page, pageSize, {
        search: searchTerm,
        fromDate,
        toDate,
        sortBy: SORT_FIELD_MAP[sortBy] || sortBy,
        sortOrder,
      });

      if (!res || res.status_code !== 200) {
        setQuotations([]);
        return;
      }

      const raw = Array.isArray(res.data?.quotations)
        ? res.data.quotations
        : [];

      setQuotations(
        raw.map((q: any) => ({
          quotationNumber: q.id || "",
          customerName: q.customerName || "N/A",
          industryBases: q.industryBases || "N/A",
          transactionDate: q.transactionDate || "",
          validTill: q.validTill || "",
          grandTotal: Number(q.grandTotal ?? 0),
          currency: q.currency || "ZMW",
        })),
      );

      setTotalPages(res.data?.pagination?.totalPages || 1);
      setTotalItems(res.data?.pagination?.total || raw.length);
    } catch (err) {
      console.error("Error fetching quotations:", err);
      setQuotations([]);
    } finally {
      setLoading(false);
      setInitialLoad(false);
    }
  };

  useEffect(() => {
    fetchQuotations();
  }, [page, pageSize, searchTerm, fromDate, toDate, sortBy, sortOrder]);

  // ── Sort handler — store column key in state, map to backend at call site ─
  const handleSortChange = ({
    sortBy: colKey,
    sortOrder: order,
  }: {
    sortBy: string;
    sortOrder: "asc" | "desc";
  }) => {
    setSortBy(colKey); // ← always the column key e.g. "quotationNumber"
    setSortOrder(order);
    setPage(1);
  };

  const handleOpenReceipt = (receiptUrl: string) => {
    const normalizedUrl = receiptUrl.startsWith("http://")
      ? receiptUrl.replace(/^http:\/\//i, "https://")
      : receiptUrl;

    const urlWithoutPort = (() => {
      try {
        const u = new URL(normalizedUrl);
        u.port = "";
        return u.toString();
      } catch {
        return normalizedUrl.replace(
          /^(https?:\/\/[^\/]+):\d+(\/.*)?$/i,
          "$1$2",
        );
      }
    })();

    const a = document.createElement("a");
    a.href = urlWithoutPort;
    a.target = "_blank";
    a.rel = "noopener noreferrer";
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

  const fetchAllForExport = async (): Promise<QuotationSummary[]> => {
    let allData: QuotationSummary[] = [];
    let current = 1;
    let total = 1;

    do {
      const res = await getAllQuotations(current, 100, {
        search: searchTerm,
        fromDate,
        toDate,
        sortBy: SORT_FIELD_MAP[sortBy] || sortBy, // ← same mapping
        sortOrder,
      });

      if (res?.status_code === 200) {
        const raw = res.data?.quotations || [];
        allData = [
          ...allData,
          ...raw.map((q: any) => ({
            quotationNumber: q.id || "",
            customerName: q.customerName || "N/A",
            industryBases: q.industryBases || "N/A",
            transactionDate: q.transactionDate || "",
            validTill: q.validTill || "",
            grandTotal: Number(q.grandTotal ?? 0),
            currency: q.currency || "ZMW",
          })),
        ];
        total = res.data?.pagination?.totalPages || 1;
      }

      current++;
    } while (current <= total);

    return allData;
  };

  const handleExportExcel = async () => {
    try {
      showLoading("Exporting Quotations...");
      const data = await fetchAllForExport();

      if (!data.length) {
        closeSwal();
        showApiError("No quotations to export");
        return;
      }

      const worksheet = XLSX.utils.json_to_sheet(
        data.map((q) => ({
          "Quotation No": q.quotationNumber,
          Customer: q.customerName,
          Industry: q.industryBases,
          Date: q.transactionDate,
          "Valid Till": q.validTill,
          Amount: q.grandTotal,
          Currency: q.currency,
        })),
      );

      const workbook = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(workbook, worksheet, "Quotations");

      saveAs(
        new Blob([XLSX.write(workbook, { bookType: "xlsx", type: "array" })], {
          type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
        }),
        "All_Quotations.xlsx",
      );

      closeSwal();
      showSuccess("Export completed successfully");
    } catch (err) {
      closeSwal();
      showApiError(err);
    }
  };

  const handleView = (quotationNumber: string, e?: React.MouseEvent) => {
    e?.stopPropagation();
    setDetailsId(quotationNumber);
    setDetailsOpen(true);
  };

  const handleDownload = async (
    quotationNumber: string,
    e?: React.MouseEvent,
  ) => {
    e?.stopPropagation();
    try {
      showLoading("Preparing quotation download...");

      if (!company) {
        closeSwal();
        console.error("Company data not loaded");
        return;
      }

      const res = await getQuotationById(quotationNumber);
      if (!res || res.status_code !== 200) {
        closeSwal();
        showApiError("Failed to load quotation");
        return;
      }

      await generateQuotationPDF(res.data, company, "save");
      closeSwal();
      showSuccess("Quotation downloaded");
    } catch (err: any) {
      closeSwal();
      showApiError(err);
    }
  };

  const mapQuotationToInvoiceDetails = (raw: any): InvoiceDetails => {
    const items = Array.isArray(raw?.items)
      ? raw.items.map((it: any) => ({
          itemCode: it?.itemCode,
          itemName: it?.itemName,
          quantity: Number(it?.quantity ?? 0),
          description: it?.description,
          discount: Number(it?.discount ?? 0),
          price: Number(it?.price ?? 0),
          vatCode: it?.vatCode,
          vatTaxableAmount: it?.vatTaxableAmount ?? it?.itemTotal,
        }))
      : [];

    return {
      invoiceNumber: raw?.id ?? raw?.quotationNumber,
      invoiceType: raw?.invoiceType ?? "Quotation",
      customerName: raw?.customerName ?? raw?.customerId,
      customerTpin: raw?.customerTpin,
      currencyCode: raw?.currencyCode,
      exchangeRt: raw?.exchangeRt,
      dateOfInvoice: raw?.transactionDate,
      dueDate: raw?.validUntil ?? raw?.validTill,
      Receipt: raw?.Receipt ?? raw?.receipt,
      ReceiptNo: raw?.ReceiptNo ?? raw?.receiptNo,
      TotalAmount: raw?.TotalAmount ?? raw?.grandTotal ?? raw?.totalAmount,
      discountPercentage: raw?.discountPercentage,
      discountAmount: raw?.discountAmount,
      lpoNumber: raw?.lpoNumber,
      destnCountryCd: raw?.destnCountryCd,
      billingAddress: raw?.billingAddress,
      shippingAddress: raw?.shippingAddress,
      paymentInformation: raw?.paymentInformation,
      items,
      terms: raw?.terms,
    };
  };

  const columns: Column<QuotationSummary>[] = [
    {
      key: "quotationNumber",
      header: "Quotation No",
      align: "left",
      sortable: true,
      render: (q) => (
        <span className="font-semibold text-main">{q.quotationNumber}</span>
      ),
    },
    {
      key: "customerName",
      header: "Customer",
      align: "left",
      sortable: true,
    },
    { key: "industryBases", header: "Industry", align: "left" },
    {
      key: "transactionDate",
      header: "Date",
      align: "left",
      sortable: true,
    },
    { key: "validTill", header: "Valid Till", align: "left", sortable: true },
    {
      key: "grandTotal",
      header: "Amount",
      align: "right",
      sortable: true,
      render: (q) => (
        <code className="text-xs px-2 py-1 rounded bg-row-hover text-main">
          {q.currency} {q.grandTotal.toLocaleString()}
        </code>
      ),
    },
    {
      key: "actions",
      header: "Actions",
      align: "center",
      render: (q) => (
        <ActionGroup>
          <ActionButton
            type="view"
            onClick={(e) => handleView(q.quotationNumber, e)}
            iconOnly
          />
          <ActionMenu
            showDownload
            onDownload={(e) => handleDownload(q.quotationNumber, e)}
          />
        </ActionGroup>
      ),
    },
  ];

  return (
    <div className="p-8">
      <Table
        columns={columns}
        data={quotations}
        rowKey={(row) => row.quotationNumber}
        loading={loading || initialLoad}
        showToolbar
        searchValue={searchTerm}
        onSearch={(q) => {
          setSearchTerm(q);
          setPage(1);
        }}
        enableColumnSelector
        enableAdd
        addLabel="Add Quotation"
        onAdd={onAddQuotation}
        enableExport
        onExport={handleExportExcel}
        currentPage={page}
        totalPages={totalPages}
        pageSize={pageSize}
        totalItems={totalItems}
        pageSizeOptions={[10, 25, 50, 100]}
        onPageSizeChange={(size) => {
          setPageSize(size);
          setPage(1);
        }}
        onPageChange={setPage}
        sortBy={sortBy}
        sortOrder={sortOrder}
        onSortChange={handleSortChange}
      />

      <InvoiceDetailsModal
        open={detailsOpen}
        invoiceId={detailsId}
        onClose={() => {
          setDetailsOpen(false);
          setDetailsId(null);
        }}
        fetchDetails={getQuotationById}
        onOpenReceiptPdf={handleOpenReceipt}
        mapDetails={mapQuotationToInvoiceDetails}
      />
    </div>
  );
};

